import hashlib import json import logging import os import re import sqlite3 import time import uuid from pathlib import Path from typing import Any from google.adk.agents.base_agent import BaseAgent from google.adk.agents.callback_context import CallbackContext from google.adk.agents.invocation_context import InvocationContext from google.adk.events.event import Event from google.adk.models.llm_request import LlmRequest from google.adk.models.llm_response import LlmResponse from google.adk.plugins.base_plugin import BasePlugin from google.adk.tools.base_tool import BaseTool from google.adk.tools.tool_context import ToolContext from google.genai import types from rlm_adk.state import ( CONTEXT_WINDOW_SNAPSHOT, DYN_SKILL_INSTRUCTION, FINAL_ANSWER, INVOCATION_START_TIME, ITERATION_COUNT, LAST_REPL_RESULT, OBS_CHILD_TOTAL_BATCH_DISPATCHES, OBS_TOTAL_CALLS, OBS_TOTAL_INPUT_TOKENS, OBS_TOTAL_OUTPUT_TOKENS, REASONING_PARSED_OUTPUT, REASONING_RAW_OUTPUT, REASONING_THOUGHT_TEXT, REASONING_VISIBLE_OUTPUT_TEXT, ) ⋮---- logger = logging.getLogger(__name__) ⋮---- _DEPTH_FANOUT_RE = re.compile(r'^(.+)@d(\d+)(?:f(\d+))?$') ⋮---- def _parse_key(raw_key: str) -> tuple[str, int, int | None]: """Parse depth/fanout suffix from a state key.
Returns (base_key, depth, fanout_or_None). """ ⋮---- def _categorize_key(key: str) -> str: """Categorize a state key for the session_state_events table.""" ⋮---- _CURATED_PREFIXES = ( "obs:", "artifact_", "last_repl_result", "repl_submitted_code", "repl_expanded_code", "repl_skill_expansion_meta", "repl_did_expand", ) ⋮---- _CURATED_EXACT = { "iteration_count", "should_stop", "final_answer", "policy_violation", "request_id", "idempotency_key", "repo_url", "root_prompt", "skill_instruction", "enabled_skills", "cache:hit_count", "cache:miss_count", "cache:last_hit_key", "worker_dispatch_count", REASONING_VISIBLE_OUTPUT_TEXT, REASONING_THOUGHT_TEXT, REASONING_RAW_OUTPUT, REASONING_PARSED_OUTPUT, } ⋮---- _FULL_TEXT_SSE_KEYS = { REASONING_VISIBLE_OUTPUT_TEXT, REASONING_THOUGHT_TEXT, REASONING_RAW_OUTPUT, } ⋮---- def _should_capture(base_key: str) -> bool: """Return True if this key should be captured in session_state_events.""" ⋮---- def _typed_value(value: Any) -> tuple[str, int | None, float | None, str | None, str | None]: """Return (value_type, value_int, value_float, value_text, value_json).""" ⋮---- def _typed_value_for_key( base_key: str, value: Any, ) -> tuple[str, int | None, float | None, str | None, str | None]: """Return a typed row payload, preserving full text for live-inspection keys.""" ⋮---- def _serialize_payload(value: Any) -> str | None: """Serialize arbitrary telemetry payloads without truncation.""" ⋮---- _SCHEMA_SQL = """ CREATE TABLE IF NOT EXISTS traces ( trace_id TEXT PRIMARY KEY, session_id TEXT NOT NULL, user_id TEXT, app_name TEXT, start_time REAL NOT NULL, end_time REAL, status TEXT DEFAULT 'running', total_input_tokens INTEGER DEFAULT 0, total_output_tokens INTEGER DEFAULT 0, total_calls INTEGER DEFAULT 0, iterations INTEGER DEFAULT 0, final_answer_length INTEGER, metadata TEXT, request_id TEXT, repo_url TEXT, root_prompt_preview TEXT, total_execution_time_s REAL, child_dispatch_count INTEGER, child_total_batch_dispatches INTEGER, child_error_counts TEXT, structured_output_failures INTEGER, finish_safety_count INTEGER, finish_recitation_count INTEGER, finish_max_tokens_count INTEGER, tool_invocation_summary TEXT, artifact_saves INTEGER, artifact_bytes_saved INTEGER, per_iteration_breakdown TEXT, model_usage_summary TEXT, config_json TEXT, prompt_hash TEXT, max_depth_reached INTEGER );
CREATE TABLE IF NOT EXISTS spans ( span_id TEXT PRIMARY KEY, trace_id TEXT NOT NULL, parent_span_id TEXT, operation_name TEXT NOT NULL, agent_name TEXT, start_time REAL NOT NULL, end_time REAL, status TEXT DEFAULT 'ok', attributes TEXT, events TEXT );
CREATE TABLE IF NOT EXISTS telemetry ( telemetry_id TEXT PRIMARY KEY, trace_id TEXT NOT NULL, event_type TEXT NOT NULL, agent_name TEXT, iteration INTEGER, depth INTEGER DEFAULT 0, call_number INTEGER, start_time REAL NOT NULL, end_time REAL, duration_ms REAL, model TEXT, input_tokens INTEGER, output_tokens INTEGER, thought_tokens INTEGER, finish_reason TEXT, num_contents INTEGER, agent_type TEXT, prompt_chars INTEGER, system_chars INTEGER, tool_name TEXT, tool_args_keys TEXT, result_preview TEXT, repl_has_errors INTEGER, repl_has_output INTEGER, repl_llm_calls INTEGER, repl_stdout_len INTEGER, repl_stderr_len INTEGER, repl_trace_summary TEXT, skill_instruction TEXT, result_payload TEXT, repl_stdout TEXT, repl_stderr TEXT, status TEXT DEFAULT 'ok', error_type TEXT, error_message TEXT );
CREATE TABLE IF NOT EXISTS session_state_events ( event_id TEXT PRIMARY KEY, trace_id TEXT NOT NULL, seq INTEGER NOT NULL, event_author TEXT, event_time REAL NOT NULL, state_key TEXT NOT NULL, key_category TEXT NOT NULL, key_depth INTEGER DEFAULT 0, key_fanout INTEGER, value_type TEXT, value_int INTEGER, value_float REAL, value_text TEXT, value_json TEXT );
CREATE INDEX IF NOT EXISTS idx_spans_trace_id ON spans(trace_id); CREATE INDEX IF NOT EXISTS idx_spans_operation ON spans(operation_name); CREATE INDEX IF NOT EXISTS idx_traces_session ON traces(session_id); CREATE INDEX IF NOT EXISTS idx_traces_start ON traces(start_time); CREATE INDEX IF NOT EXISTS idx_telemetry_trace ON telemetry(trace_id); CREATE INDEX IF NOT EXISTS idx_telemetry_type ON telemetry(event_type); CREATE INDEX IF NOT EXISTS idx_sse_trace ON session_state_events(trace_id); CREATE INDEX IF NOT EXISTS idx_sse_key ON session_state_events(state_key); CREATE INDEX IF NOT EXISTS idx_sse_trace_seq ON session_state_events(trace_id, seq); """ ⋮---- class SqliteTracingPlugin(BasePlugin): """ADK Plugin that writes structured telemetry to a local SQLite database.
Uses a 3-table schema: - traces: One row per invocation, enriched with OBS keys at run end. - telemetry: One row per model call or tool invocation (structured columns). - session_state_events: One row per curated state key change from events.
The legacy ``spans`` table is retained for backward compatibility but no longer receives new writes.
The plugin is observe-only: all callbacks return None and never block execution. Database write errors are caught and logged as warnings.
Args: name: Plugin name (default "sqlite_tracing"). db_path: Path to the SQLite database file (default ".adk/traces.db"). Created if it does not exist. Parent directories are created. """ ⋮---- def __init__( self, *, name: str = "sqlite_tracing", db_path: str = ".adk/traces.db", ): ⋮---- def _init_db(self) -> None: """Initialize the database connection and create tables.""" ⋮---- def _migrate_schema(self) -> None: """Add missing columns to existing tables.
CREATE TABLE IF NOT EXISTS is a no-op for tables that already exist but have fewer columns than the current schema. This method inspects existing columns via PRAGMA table_info and adds any missing ones. """ ⋮---- def _new_id(self) -> str: """Generate a new unique ID.""" ⋮---- @staticmethod ⋮---- @staticmethod def _pending_key(obj: Any) -> int: """Return a stable in-process key for pairing before/after callbacks.""" ⋮---- @staticmethod def _coerce_int(value: Any, default: int = 0) -> int: """Best-effort integer coercion for callback payloads and mocks.""" ⋮---- @staticmethod def _resolve_repl_state( state: Any, *, tool_depth: int | None, ) -> dict[str, Any] | None: """Select the best-matching last_repl_result payload from tool state.""" ⋮---- def _insert_telemetry( self, telemetry_id: str, event_type: str, start_time: float, **kwargs: Any, ) -> None: """Insert a telemetry row.""" ⋮---- def _update_telemetry(self, telemetry_id: str, **kwargs: Any) -> None: """Update a telemetry row with additional fields.""" ⋮---- def _insert_sse( self, raw_key: str, value: Any, author: str | None, event_time: float, ) -> None: """Insert a session_state_events row for a curated key.""" ⋮---- async def before_run_callback( self, *, invocation_context: InvocationContext ) -> types.Content | None: """Create a new trace row for this invocation.""" ⋮---- async def after_run_callback( self, *, invocation_context: InvocationContext ) -> None: """Finalize the trace row with summary stats and enriched columns.""" ⋮---- async def before_agent_callback( self, *, agent: BaseAgent, callback_context: CallbackContext ) -> types.Content | None: """Track agent name for parent context (no span write).""" ⋮---- async def after_agent_callback( self, *, agent: BaseAgent, callback_context: CallbackContext ) -> types.Content | None: """Pop agent from context stack.""" ⋮---- async def before_model_callback( self, *, callback_context: CallbackContext, llm_request: LlmRequest ) -> LlmResponse | None: """Insert a telemetry row for model_call and store ID for pairing.""" ⋮---- async def after_model_callback( self, *, callback_context: CallbackContext, llm_response: LlmResponse ) -> LlmResponse | None: """Update telemetry row with tokens, finish_reason, duration.""" ⋮---- async def on_model_error_callback( self, *, callback_context: CallbackContext, llm_request: LlmRequest, error: Exception, ) -> LlmResponse | None: """Mark the pending model telemetry row as an error.""" ⋮---- async def before_tool_callback( self, *, tool: BaseTool, tool_args: dict[str, Any], tool_context: ToolContext, ) -> dict | None: """Insert a telemetry row for tool_call.""" ⋮---- async def after_tool_callback( self, *, tool: BaseTool, tool_args: dict[str, Any], tool_context: ToolContext, result: dict, ) -> dict | None: """Update the tool telemetry row with result preview and duration.""" ⋮---- async def on_event_callback( self, *, invocation_context: InvocationContext, event: Event ) -> Event | None: """Capture curated state_delta keys as session_state_events rows.""" ⋮---- async def close(self) -> None: """Close the database connection."""

